let originalConsole={log:console.log,error:console.error,warn:console.warn,info:console.info};function overrideConsole(){console.log=(...e)=>{const o=e.map(e=>"object"==typeof e?JSON.stringify(e):String(e)).join(" ")+"\n";self.postMessage({type:"stdout",output:o}),originalConsole.log(...e)},console.error=(...e)=>{const o=e.map(e=>"object"==typeof e?JSON.stringify(e):String(e)).join(" ")+"\n";self.postMessage({type:"stderr",output:o}),originalConsole.error(...e)},console.warn=(...e)=>{const o=e.map(e=>"object"==typeof e?JSON.stringify(e):String(e)).join(" ")+"\n";self.postMessage({type:"stderr",output:o}),originalConsole.warn(...e)},console.info=(...e)=>{const o=e.map(e=>"object"==typeof e?JSON.stringify(e):String(e)).join(" ")+"\n";self.postMessage({type:"stdout",output:o}),originalConsole.info(...e)}}self.onmessage=function(event){const{id,type,payload}=event.data;if("startJsWorker"===type)overrideConsole(),self.postMessage({id,success:!0,result:{status:"started"}});else if("execute"===type)try{const result=eval(payload.code);self.postMessage({id,success:!0,result:{result:String(result)}})}catch(e){self.postMessage({id,success:!1,error:e.message})}};